import{_ as t,o,c as r,a5 as a}from"./chunks/framework.CiafrMtK.js";const u=JSON.parse('{"title":"Code-based provider quick start","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/code-based-provider-quick-start.md","filePath":"tutorials/code-based-provider-quick-start.md"}'),i={name:"tutorials/code-based-provider-quick-start.md"};function s(c,e,d,l,n,h){return o(),r("div",null,[...e[0]||(e[0]=[a(`<h1 id="code-based-provider-quick-start" tabindex="-1">Code-based provider quick start <a class="header-anchor" href="#code-based-provider-quick-start" aria-label="Permalink to &quot;Code-based provider quick start&quot;">​</a></h1><p>This quickstart is for cases where your provider ships its own controller (operator), CRDs, and optionally a custom UI microfrontend. It is the companion to the <a href="./provider-quick-start.html">No-code provider quick start</a>, which uses api-syncagent to expose an existing CRD with no provider-specific code.</p><p>The reference implementation is the <strong>Wild West provider</strong>, which exposes a <code>Cowboys</code> API under the <code>wildwest.platform-mesh.io</code> group. The full walkthrough lives next to the code, in the <a href="https://github.com/platform-mesh/provider-quickstart" target="_blank" rel="noreferrer">provider-quickstart</a> repository — we keep it there rather than duplicating it here so the steps stay in sync with the code, charts, and <code>make</code> targets you actually run.</p><div class="tip custom-block"><p class="custom-block-title">Requires a local clone</p><p>Unlike the no-code quickstart, this one builds and runs code from the <code>provider-quickstart</code> repo. Clone it first — every step in the upstream guide is executed from inside that directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/platform-mesh/provider-quickstart.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> provider-quickstart</span></span></code></pre></div></div><h2 id="follow-the-walkthrough" tabindex="-1">Follow the walkthrough <a class="header-anchor" href="#follow-the-walkthrough" aria-label="Permalink to &quot;Follow the walkthrough&quot;">​</a></h2><p>Run through the upstream guide end-to-end:</p><p><strong>→ <a href="https://github.com/platform-mesh/provider-quickstart#usage" target="_blank" rel="noreferrer">provider-quickstart: Usage</a></strong></p><p>It covers:</p><ol><li>Setting the admin and compute kubeconfigs.</li><li>Creating the provider workspace hierarchy (<code>root:providers:quickstart</code>).</li><li>Bootstrapping provider resources (<code>make init</code>) — applies the <code>APIExport</code>, <code>APIResourceSchema</code>, <code>ProviderMetadata</code>, <code>ContentConfiguration</code>, and RBAC.</li><li>Building and loading container images into the local kind cluster.</li><li>Deploying the <code>wild-west</code> controller, <code>armament-sync</code> syncer, and portal microfrontend.</li><li>Trying it out — creating <code>Cowboy</code> resources with secret refs and using the <code>Armament</code> catalog (a kcp <code>CachedResource</code>) from a consumer workspace.</li><li>Debugging via the <code>marketplace</code> and <code>contentconfigurations</code> virtual workspaces.</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A local Platform Mesh setup from <a href="/pr-preview/pr-241/how-to-guides/set-up-platform-mesh-locally.html">Set up Platform Mesh locally</a>.</li><li>A local clone of <a href="https://github.com/platform-mesh/provider-quickstart" target="_blank" rel="noreferrer">provider-quickstart</a> (see the tip above).</li><li><code>kubectl</code> with the <code>kubectl-kcp</code> plugin, Helm 3, Go, and <code>make</code>.</li></ul><div class="warning custom-block"><p class="custom-block-title">Admin kubeconfig required</p><p>Providers live in a dedicated workspace tree, so you need the <strong>admin kubeconfig</strong> to create the provider workspace and bootstrap resources. Regular user kubeconfigs will not have the required permissions today.</p></div><h2 id="how-it-relates-to-platform-mesh-concepts" tabindex="-1">How it relates to Platform Mesh concepts <a class="header-anchor" href="#how-it-relates-to-platform-mesh-concepts" aria-label="Permalink to &quot;How it relates to Platform Mesh concepts&quot;">​</a></h2><p>The four building blocks the upstream walkthrough exercises are documented here:</p><table tabindex="0"><thead><tr><th>Building block</th><th>Reference</th></tr></thead><tbody><tr><td><code>APIExport</code> / <code>APIResourceSchema</code></td><td><a href="/pr-preview/pr-241/concepts/api-sharing.html">API sharing</a></td></tr><tr><td><code>ProviderMetadata</code> (Marketplace registration)</td><td><a href="/pr-preview/pr-241/reference/components/marketplace.html">Marketplace</a></td></tr><tr><td><code>ContentConfiguration</code> (portal UI)</td><td><a href="/pr-preview/pr-241/reference/resources/content-configuration.html">ContentConfiguration</a></td></tr><tr><td><code>CachedResource</code> (read-only catalogs to consumers)</td><td><a href="/pr-preview/pr-241/reference/components/kcp/virtual-workspaces.html">Virtual workspaces</a></td></tr></tbody></table><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li>Use the <code>provider-quickstart</code> repo as a template — fork it, replace <code>wildwest.platform-mesh.io</code> with your API group, define your CRD schema, and update <code>ProviderMetadata</code> and <code>ContentConfiguration</code>.</li><li>Continue with <a href="./consume-service-from-controller.html">Consume a service from a controller</a> to write the consumer side.</li></ul>`,17)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
